+// ─── Floor tile patterns ─────────────────────────────────────────────
+
+function tileStone(ctx: CanvasRenderingContext2D) {
+  const size = 16;
+  ctx.fillStyle = '#7a7a7a';
+  ctx.fillRect(0, 0, size, size);
+  ctx.strokeStyle = '#5a5a5a';
+  ctx.lineWidth = 1;
+  // Draw mortar lines
+  ctx.beginPath();
+  ctx.moveTo(0, 4);
+  ctx.lineTo(size, 4);
+  ctx.moveTo(0, 12);
+  ctx.lineTo(size, 12);
+  ctx.moveTo(4, 0);
+  ctx.lineTo(4, size);
+  ctx.moveTo(12, 0);
+  ctx.lineTo(12, size);
+  ctx.stroke();
+  // Draw stone texture blocks
+  ctx.fillStyle = '#8a8a8a';
+  ctx.fillRect(1, 1, 3, 3);
+  ctx.fillRect(5, 1, 6, 3);
+  ctx.fillRect(13, 1, 2, 3);
+  ctx.fillRect(1, 5, 3, 6);
+  ctx.fillRect(5, 5, 6, 6);
+  ctx.fillRect(13, 5, 2, 6);
+  ctx.fillRect(1, 13, 3, 2);
+  ctx.fillRect(5, 13, 6, 2);
+  ctx.fillRect(13, 13, 2, 2);
+}
+
+function tileWood(ctx: CanvasRenderingContext2D) {
+  const size = 16;
+  ctx.fillStyle = '#8b5a2b';
+  ctx.fillRect(0, 0, size, size);
+  ctx.strokeStyle = '#6b3e14';
+  ctx.lineWidth = 1;
+  // Horizontal planks lines
+  for (let y = 2; y < size; y += 4) {
+    ctx.beginPath();
+    ctx.moveTo(0, y);
+    ctx.lineTo(size, y);
+    ctx.stroke();
+  }
+  // Wood grain pattern
+  ctx.strokeStyle = '#a06a3a';
+  ctx.lineWidth = 0.5;
+  for (let i = 0; i < 3; i++) {
+    const y = 1 + i * 5;
+    ctx.beginPath();
+    ctx.moveTo(2, y);
+    ctx.bezierCurveTo(6, y + 1, 10, y - 1, 14, y + 1);
+    ctx.stroke();
+  }
+}
+
+function tileCarpet(ctx: CanvasRenderingContext2D) {
+  const size = 16;
+  ctx.fillStyle = '#b22222';
+  ctx.fillRect(0, 0, size, size);
+  // Border pattern
+  ctx.strokeStyle = '#7f0000';
+  ctx.lineWidth = 2;
+  ctx.strokeRect(1, 1, size - 2, size - 2);
+  ctx.strokeStyle = '#d04040';
+  ctx.lineWidth = 1;
+  // Small diamond pattern inside
+  ctx.beginPath();
+  ctx.moveTo(size / 2, 3);
+  ctx.lineTo(size - 3, size / 2);
+  ctx.lineTo(size / 2, size - 3);
+  ctx.lineTo(3, size / 2);
+  ctx.closePath();
+  ctx.stroke();
+}
+
+function tileCobblestone(ctx: CanvasRenderingContext2D) {
+  const size = 16;
+  ctx.fillStyle = '#6b6b6b';
+  ctx.fillRect(0, 0, size, size);
+  ctx.fillStyle = '#8c8c8c';
+  // Draw irregular circles as cobblestones
+  ctx.beginPath();
+  ctx.ellipse(4, 5, 3, 2.5, 0.2, 0, Math.PI * 2);
+  ctx.ellipse(11, 4, 4, 3, -0.3, 0, Math.PI * 2);
+  ctx.ellipse(7, 11, 3.5, 3, 0.1, 0, Math.PI * 2);
+  ctx.ellipse(13, 12, 2.5, 2, -0.2, 0, Math.PI * 2);
+  ctx.fill();
+  ctx.strokeStyle = '#4a4a4a';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.ellipse(4, 5, 3, 2.5, 0.2, 0, Math.PI * 2);
+  ctx.ellipse(11, 4, 4, 3, -0.3, 0, Math.PI * 2);
+  ctx.ellipse(7, 11, 3.5, 3, 0.1, 0, Math.PI * 2);
+  ctx.ellipse(13, 12, 2.5, 2, -0.2, 0, Math.PI * 2);
+  ctx.stroke();
+}
