+// ─── Draw tiled floor with thematic tile ─────────────────────────────
+
+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, type: CharacterType) {
+  // Select tile pattern function by room type theme
+  let tileFunc: (ctx: CanvasRenderingContext2D) => void;
+  switch (type) {
+    case 'king':
+    case 'nobility':
+      tileFunc = tileCarpet;
+      break;
+    case 'knight':
+    case 'squire':
+      tileFunc = tileStone;
+      break;
+    case 'healer':
+    case 'sentinel':
+      tileFunc = tileWood;
+      break;
+    case 'scribe':
+    case 'judge':
+    case 'blacksmith':
+      tileFunc = tileCobblestone;
+      break;
+    default:
+      tileFunc = tileStone;
+  }
+
+  const tileSize = 16;
+  // Create offscreen canvas for tile pattern
+  const tileCanvas = document.createElement('canvas');
+  tileCanvas.width = tileSize;
+  tileCanvas.height = tileSize;
+  const tileCtx = tileCanvas.getContext('2d');
+  if (!tileCtx) return;
+  tileCtx.clearRect(0, 0, tileSize, tileSize);
+  tileFunc(tileCtx);
+
+  // Create pattern and fill floor area
+  const pattern = ctx.createPattern(tileCanvas, 'repeat');
+  if (!pattern) return;
+  ctx.fillStyle = pattern;
+  ctx.fillRect(x, y, w, h);
+}
